 3→internal const val BLANK_LINE_CHAR = "|"
 4→internal const val WILDCARD_CHAR = "*"
 5→internal const val ALIAS_CHAR = "^"
 6→
 7→/**
 8→ * Adapted from https://github.com/JetBrains/intellij-kotlin/blob/73b5a484198f02518c9ece2fb453d27cead680fb/idea/src/org/jetbrains/kotlin/idea/formatter/KotlinPackageEntryTableAccessor.kt#L27-L43
 9→ */
10→internal fun parseImportsLayout(importsLayout: String): List<PatternEntry> {
11→    val importsList = importsLayout.split(",").map { it.trim() }
12→
13→    if (importsList.first() == BLANK_LINE_CHAR || importsList.last() == BLANK_LINE_CHAR) {
14→        throw IllegalArgumentException("Blank lines are not supported in the beginning or end of import list")
15→    }
16→
17→    if (WILDCARD_CHAR !in importsList) {
18→        throw IllegalArgumentException("<all other imports> symbol (\"*\") must be present in the custom imports layout")
19→    }
20→
21→    return importsList.map {
22→        var import = it
23→        if (import == BLANK_LINE_CHAR) {
24→            return@map PatternEntry.BLANK_LINE_ENTRY
25→        } else {
26→            var hasAlias = false
27→            var withSubpackages = false
28→            if (import.startsWith(ALIAS_CHAR)) {
29→                import = import.substring(1).trim()
30→                hasAlias = true
31→            }
32→            if (import.endsWith(WILDCARD_CHAR + WILDCARD_CHAR)) { // java.**
33→                import = import.substringBeforeLast(WILDCARD_CHAR)
34→                withSubpackages = true
35→            }
36→            return@map if (import == WILDCARD_CHAR) { // *
37→                PatternEntry.ALL_OTHER_IMPORTS_ENTRY
38→            } else if (import.isEmpty() && hasAlias) { // ^
39→                PatternEntry.ALL_OTHER_ALIAS_IMPORTS_ENTRY
40→            } else {
41→                PatternEntry(import, withSubpackages, hasAlias)
42→            }
43→        }
44→    }
45→}
